#!/usr/bin/env bash
# Verify baseline structure for harness two-plugin refactor.
# Generated by the initializer agent — no dev server needed for this refactoring project.
set -e

ROOT="$(cd "$(dirname "$0")/.." && pwd)"
CORE_SKILLS="$ROOT/plugins/harness/skills"
FAIL=0

echo "=== Harness v2.0.0 Refactor — Baseline Smoke Test ==="

# 1. Verify core skill exists
if [ -f "$CORE_SKILLS/harness/SKILL.md" ]; then
  echo "OK — core skill exists"
else
  echo "FAIL — core skill not found at $CORE_SKILLS/harness/SKILL.md"
  FAIL=$((FAIL + 1))
fi

# 2. Verify 5 domain skills exist (pre-refactor baseline)
for SKILL in harness-sdlc harness-ea harness-ba harness-sa harness-ops; do
  if [ -f "$CORE_SKILLS/$SKILL/SKILL.md" ]; then
    echo "OK — domain skill $SKILL exists in core plugin (pre-refactor)"
  elif [ -f "$ROOT/plugins/harness-sdlc-suite/skills/$SKILL/SKILL.md" ]; then
    echo "OK — domain skill $SKILL exists in sdlc-suite plugin (post-refactor)"
  else
    echo "FAIL — domain skill $SKILL not found in either location"
    FAIL=$((FAIL + 1))
  fi
done

# 3. Verify manifests exist and are valid JSON
for MANIFEST in "$ROOT/.claude-plugin/marketplace.json" "$ROOT/.codex-plugin/plugin.json"; do
  if [ -f "$MANIFEST" ]; then
    if python3 -c "import json; json.load(open('$MANIFEST'))" 2>/dev/null || \
       python -c "import json; json.load(open('$MANIFEST'))" 2>/dev/null; then
      echo "OK — $MANIFEST is valid JSON"
    else
      echo "WARN — $MANIFEST exists but JSON validation skipped (no python)"
    fi
  else
    echo "FAIL — $MANIFEST not found"
    FAIL=$((FAIL + 1))
  fi
done

# 4. Verify install scripts exist
for SCRIPT in "$ROOT/install.sh" "$ROOT/install.bat"; do
  if [ -f "$SCRIPT" ]; then
    echo "OK — $SCRIPT exists"
  else
    echo "FAIL — $SCRIPT not found"
    FAIL=$((FAIL + 1))
  fi
done

# 5. Verify README exists
if [ -f "$ROOT/README.md" ]; then
  echo "OK — README.md exists"
else
  echo "FAIL — README.md not found"
  FAIL=$((FAIL + 1))
fi

echo ""
if [ "$FAIL" -gt 0 ]; then
  echo "FAIL — $FAIL check(s) failed"
  exit 1
fi

echo "OK — baseline smoke test passed"
